public class Knapsack { public static int knapsack(int[] weights, int[] values, int capacity) { int[][] dp = new int[values.length+1][capacity+1]; for(int i = 1; i <= values.length; i++) for(int w = 1; w <= capacity; w++) if(weights[i-1] <= w) dp[i][w] = Math.max(values[i-1] + dp[i-1][w-weights[i-1]], dp[i-1][w]); else dp[i][w] = dp[i-1][w]; return dp[values.length][capacity]; } }